def search(nums: list[int], target: int) -> int:
    left, right = 0, len(nums) - 1

    while left <= right:
        mid = (left + right) // 2

        if nums[mid] == target:
            return mid

        # Sol taraf sıralı mı? (nums[left] <= nums[mid] ise)
        if nums[left] <= nums[mid]:
            # Hedef sol tarafta mı? (nums[left] <= target < nums[mid] ise)
            if nums[left] <= target < nums[mid]:
                right = mid - 1
            else:
                # Hedef sağ tarafta (unsorted)
                left = mid + 1
        # Sağ taraf sıralı (nums[left] > nums[mid] ise)
        else:
            # Hedef sağ tarafta mı? (nums[mid] < target <= nums[right] ise)
            if nums[mid] < target <= nums[right]:
                left = mid + 1
            else:
                # Hedef sol tarafta (unsorted)
                right = mid - 1

    return -1
